func (r *receiverImpl) Start(ctx context.Context, host component.Host) error {
	ctx, cancel := context.WithCancel(ctx)
	r.cancel = cancel
	go func() {
		if err := r.readLoop(ctx); err != nil {
			// TODO: handle error
		}
	}()
	return nil
}

func (r *receiverImpl) Shutdown(ctx context.Context) error {
	if r.cancel != nil {
		r.cancel()
	}
	return nil
}

